from datetime import datetime, timedelta

def simulate_fort_hood_43_timeline():
    events = []

    # April 4, 1968: MLK assassination leads to deployment orders
    events.append({
        "date": datetime(1968, 4, 4),
        "event": "Martin Luther King Jr. assassinated; U.S. troops at Fort Hood receive orders to deploy to Chicago for riot control."
    })

    # August 23, 1968 (evening): Meeting of over 100 soldiers
    events.append({
        "date": datetime(1968, 8, 23, 19, 0),
        "event": "Over 100 Black soldiers from the 1st Armored Cavalry Division meet to discuss concerns about deployment."
    })

    # August 24, 1968 (midnight): Sit-in begins
    events.append({
        "date": datetime(1968, 8, 24, 0, 0),
        "event": "Sixty troops stage a nonviolent sit-in at a major base intersection to protest deployment."
    })

    # August 24, 1968 (5:00 AM): Meeting with Maj. Gen. John C. Boles Jr.
    events.append({
        "date": datetime(1968, 8, 24, 5, 0),
        "event": "Maj. Gen. John C. Boles Jr. meets with protesters; 17 soldiers return to barracks while 43 continue protest."
    })

    # August 24, 1968 (morning): MPs attack protesters
    events.append({
        "date": datetime(1968, 8, 24, 8, 0),
        "event": "Military Police surround and attack the 43 protesting soldiers with bayonets and rifle butts, leading to injuries."
    })

    # Aftermath: Courts-martial and support from NAACP and The Oleo Strut
    events.append({
        "date": datetime(1968, 9, 1),
        "event": "Courts-martial begin; NAACP and The Oleo Strut provide legal support for the soldiers."
    })

    return events

# Print the timeline
for event in simulate_fort_hood_43_timeline():
    print(f"{event['date'].strftime('%Y-%m-%d %H:%M')}: {event['event']}")
